// Validate incoming payload. FastAPI sends:
//   { orderNumber, payoutId, payoutDateUnix, paymentTypeId, bankAccountId, comment }
// Defaults applied here so the UI can send minimal fields.
const body = items[0].json.body || items[0].json;
if (!body.orderNumber) throw new Error('orderNumber is required');
if (!body.payoutId) throw new Error('payoutId is required');
const dateUnix = Number(body.payoutDateUnix);
if (!Number.isFinite(dateUnix) || dateUnix <= 0) throw new Error('payoutDateUnix must be a positive unix timestamp');
return [{ json: {
  orderNumber:    String(body.orderNumber),
  payoutId:       String(body.payoutId),
  payoutDateUnix: dateUnix,
  paymentTypeId:  Number(body.paymentTypeId || 2),       // 2 = VIR / Credit Transfer
  bankAccountId:  Number(body.bankAccountId || 1),        // 1 = CityNational in staging
  comment:        body.comment || `eBay payout ${body.payoutId} - order ${body.orderNumber}`,
}}];

// Decide which invoices to pay. Skip any with remaintopay <= 0 (overshoot case:
// customer is owed money; no payment to record).
const input = $('Validate input').first().json;
const out = [];
for (const it of items) {
  const inv = it.json;
  if (!inv || !inv.id) continue;
  const remain = Number(inv.remaintopay || 0);
  if (remain <= 0) {
    // Pass-through marker so Shape response can count skipped
    out.push({ json: { _skip: true, invoiceId: String(inv.id), invoiceRef: inv.ref, reason: 'remaintopay<=0', remaintopay: remain } });
    continue;
  }
  out.push({ json: {
    _skip: false,
    invoiceId: String(inv.id),
    invoiceRef: inv.ref,
    amount: Math.round(remain * 100) / 100,
    _payload: {
      datepaye: input.payoutDateUnix,
      paymentid: input.paymentTypeId,
      closepaidinvoices: 'yes',
      accountid: input.bankAccountId,
      num_payment: input.payoutId,
      comment: input.comment + ` (invoice ${inv.ref})`,
    },
  }});
}
return out;

// Annotate each payment response with its invoice context.
const planned = $('Plan payments').all().filter(x => !x.json._skip);
const out = [];
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const ctx = planned[i].json;
  let paymentId = null;
  if (typeof resp === 'number') paymentId = resp;
  else if (typeof resp === 'string' && /^\d+$/.test(resp)) paymentId = Number(resp);
  else if (resp && typeof resp === 'object' && resp.id) paymentId = resp.id;
  if (paymentId) {
    out.push({ json: { ok: true, invoiceId: ctx.invoiceId, invoiceRef: ctx.invoiceRef, amount: ctx.amount, paymentId: String(paymentId) } });
  } else {
    const msg = (resp && resp.error && (resp.error.message || resp.error['0'])) || JSON.stringify(resp).slice(0, 200);
    out.push({ json: { ok: false, invoiceId: ctx.invoiceId, invoiceRef: ctx.invoiceRef, amount: ctx.amount, error: msg } });
  }
}
return out;

// Final response: per-invoice list + counters.
const input = $('Validate input').first().json;
const all = items.map(i => i.json);
const paid = all.filter(x => x.ok === true);
const failed = all.filter(x => x.ok === false);
const skipped = all.filter(x => x._skip);
return [{ json: {
  ok: failed.length === 0,
  orderNumber: input.orderNumber,
  payoutId: input.payoutId,
  summary: {
    paid: paid.length,
    skipped: skipped.length,
    failed: failed.length,
    totalPaid: Math.round(paid.reduce((s, x) => s + Number(x.amount || 0), 0) * 100) / 100,
  },
  payments: paid,
  skipped,
  errors: failed,
  message: paid.length === 0 && skipped.length > 0
    ? `Nothing to pay (${skipped.length} invoice${skipped.length === 1 ? '' : 's'} skipped: already paid or remaintopay <= 0).`
    : `Created ${paid.length} payment${paid.length === 1 ? '' : 's'}${skipped.length ? `, skipped ${skipped.length}` : ''}${failed.length ? `, failed ${failed.length}` : ''}.`,
}}];
